 const svgTag = /<svg[^>]*>/i;

+/**
+ * Remove elements and attributes which can execute script when the SVG is
+ * inserted into the DOM.
+ * @param {string} svgString raw SVG string
+ * @returns {string} sanitized SVG string
+ */
+const sanitizeSvgString = function (svgString) {
+    // Remove script-bearing/HTML-embedding elements entirely.
+    svgString = svgString.replace(/<\s*(script|foreignObject)\b[\s\S]*?<\s*\/\s*\1\s*>/gi, '');
+    svgString = svgString.replace(/<\s*(script|foreignObject)\b[^>]*\/\s*>/gi, '');
+
+    // Remove inline event handlers (e.g. onclick="...").
+    svgString = svgString.replace(/\s+on[a-z]+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)/gi, '');
+
+    // Remove javascript: URLs from linking attributes.
+    svgString = svgString.replace(
+        /\s+(href|xlink:href)\s*=\s*(["'])\s*javascript:[\s\S]*?\2/gi,
+        ''
+    );
+    svgString = svgString.replace(/\s+(href|xlink:href)\s*=\s*javascript:[^\s>]*/gi, '');
+
+    return svgString;
+};
+
 /**
