+    case ">=":
+      return currentVersion >= requiredVersion;
+    case "<":
+      return currentVersion < requiredVersion;
+    case "<=":
+      return currentVersion <= requiredVersion;
+    case "=":
+    case "==":
+      return currentVersion === requiredVersion;
+    default:
